14706 void SLPVectorizerPass::collectSeedInstructions(BasicBlock *BB) {
14707   // Initialize the collections. We will make a single pass over the block.
14708   Stores.clear();
14709   GEPs.clear();
14710 
14711   // Visit the store and getelementptr instructions in BB and organize them in
14712   // Stores and GEPs according to the underlying objects of their pointer
14713   // operands.
14714   for (Instruction &I : *BB) {
14715     // Ignore store instructions that are volatile or have a pointer operand
14716     // that doesn't point to a scalar type.
14717     if (auto *SI = dyn_cast<StoreInst>(&I)) {
14718       if (!SI->isSimple())
14719         continue;
14720       if (!isValidElementType(SI->getValueOperand()->getType()))
14721         continue;
14722       Stores[getUnderlyingObject(SI->getPointerOperand())].push_back(SI);
14723     }
14724 
14725     // Ignore getelementptr instructions that have more than one index, a
14726     // constant index, or a pointer operand that doesn't point to a scalar
14727     // type.
14728     else if (auto *GEP = dyn_cast<GetElementPtrInst>(&I)) {
14729       if (GEP->getNumIndices() != 1)
14730         continue;
14731       Value *Idx = GEP->idx_begin()->get();
14732       if (isa<Constant>(Idx))
14733         continue;
14734       if (!isValidElementType(Idx->getType()))
14735         continue;
14736       if (GEP->getType()->isVectorTy())
14737         continue;
14738       GEPs[GEP->getPointerOperand()].push_back(GEP);
14739     }
14740   }
14741 }
