14106 void BoUpSLP::computeMinimumValueSizes() {
14107   // We only attempt to truncate integer expressions.
14108   bool IsStoreOrInsertElt =
14109       VectorizableTree.front()->getOpcode() == Instruction::Store ||
14110       VectorizableTree.front()->getOpcode() == Instruction::InsertElement;
