14365 bool SLPVectorizerPass::runImpl(Function &F, ScalarEvolution *SE_,
14366                                 TargetTransformInfo *TTI_,
14367                                 TargetLibraryInfo *TLI_, AAResults *AA_,
14368                                 LoopInfo *LI_, DominatorTree *DT_,
14369                                 AssumptionCache *AC_, DemandedBits *DB_,
14370                                 OptimizationRemarkEmitter *ORE_) {
14371   if (!RunSLPVectorization)
14372     return false;
14373   SE = SE_;
14374   TTI = TTI_;
14375   TLI = TLI_;
14376   AA = AA_;
14377   LI = LI_;
14378   DT = DT_;
14379   AC = AC_;
14380   DB = DB_;
