14427     // Vectorize the index computations of getelementptr instructions. This
14428     // is primarily intended to catch gather-like idioms ending at
14429     // non-consecutive loads.
14430     if (!GEPs.empty()) {
14431       LLVM_DEBUG(dbgs() << "SLP: Found GEPs for " << GEPs.size()
14432                         << " underlying objects.\n");
