14632   // Store #3 can be added -> comes after store #4 with the same distance as
14633   // store #1.
14634   // Store #5 cannot be added - comes before store #4.
14635   // This logic allows to improve the compile time, we assume that the stores
14636   // after previous store with the same distance most likely have memory
14637   // dependencies and no need to waste compile time to try to vectorize them.
14638   // - Try to vectorize the sequence {1, {1, 0}, {3, 2}}.
14639   auto FillStoresSet = [&](unsigned Idx, StoreInst *SI) {
14640     for (std::pair<unsigned, StoreIndexToDistSet> &Set : SortedStores) {
14641       std::optional<int> Diff = getPointersDiff(
14642           Stores[Set.first]->getValueOperand()->getType(),
14643           Stores[Set.first]->getPointerOperand(),
14644           SI->getValueOperand()->getType(), SI->getPointerOperand(), *DL, *SE,
14645           /*StrictCheck=*/true);
