14649       if (It == Set.second.end()) {
14650         Set.second.emplace(Idx, *Diff);
14651         return;
14652       }
14653       // Try to vectorize the first found set to avoid duplicate analysis.
14654       TryToVectorize(Set.second);
14655       StoreIndexToDistSet PrevSet;
14656       PrevSet.swap(Set.second);
14657       Set.first = Idx;
14658       Set.second.emplace(Idx, 0);
14659       // Insert stores that followed previous match to try to vectorize them
14660       // with this store.
14661       unsigned StartIdx = It->first + 1;
14662       SmallBitVector UsedStores(Idx - StartIdx);
14663       // Distances to previously found dup store (or this store, since they
14664       // store to the same addresses).
14665       SmallVector<int> Dists(Idx - StartIdx, 0);
14666       for (const std::pair<unsigned, int> &Pair : reverse(PrevSet)) {
14667         // Do not try to vectorize sequences, we already tried.
14668         if (Pair.first <= It->first ||
14669             VectorizedStores.contains(Stores[Pair.first]))
14670           break;
14671         unsigned BI = Pair.first - StartIdx;
14672         UsedStores.set(BI);
14673         Dists[BI] = Pair.second - It->second;
14674       }
14675       for (unsigned I = StartIdx; I < Idx; ++I) {
14676         unsigned BI = I - StartIdx;
14677         if (UsedStores.test(BI))
14678           Set.second.emplace(I, Dists[BI]);
14679       }
14680       return;
14681     }
14682     auto &Res = SortedStores.emplace_back();
14683     Res.first = Idx;
14684     Res.second.emplace(Idx, 0);
14685   };
14686   StoreInst *PrevStore = Stores.front();
14687   for (auto [I, SI] : enumerate(Stores)) {
14688     // Check that we do not try to vectorize stores of different types.
14689     if (PrevStore->getValueOperand()->getType() !=
14690         SI->getValueOperand()->getType()) {
14691       for (auto &Set : SortedStores)
14692         TryToVectorize(Set.second);
14693       SortedStores.clear();
14694       PrevStore = SI;
14695     }
14696     FillStoresSet(I, SI);
14697   }
14698 
14699   // Final vectorization attempt.
14700   for (auto &Set : SortedStores)
14701     TryToVectorize(Set.second);
