14801     // code during codegen).
14802     auto *VecTy = FixedVectorType::get(ScalarTy, VF);
14803     if (TTI->getNumberOfParts(VecTy) == VF)
14804       continue;
14805     for (unsigned I = NextInst; I < MaxInst; ++I) {
14806       unsigned ActualVF = std::min(MaxInst - I, VF);
14807 
14808       if (!isPowerOf2_32(ActualVF))
14809         continue;
14810 
14811       if (MaxVFOnly && ActualVF < MaxVF)
14812         break;
14813       if ((VF > MinVF && ActualVF <= VF / 2) || (VF == MinVF && ActualVF < 2))
14814         break;
14815 
14816       ArrayRef<Value *> Ops = VL.slice(I, ActualVF);
14817       // Check that a previous iteration of this loop did not delete the Value.
14818       if (llvm::any_of(Ops, [&R](Value *V) {
14819             auto *I = dyn_cast<Instruction>(V);
14820             return I && R.isDeleted(I);
14821           }))
14822         continue;
14823 
14824       LLVM_DEBUG(dbgs() << "SLP: Analyzing " << ActualVF << " operations "
14825                         << "\n");
14826 
14827       R.buildTree(Ops);
14828       if (R.isTreeTinyAndNotFullyVectorizable())
14829         continue;
14830       R.reorderTopToBottom();
14831       R.reorderBottomToTop(
14832           /*IgnoreReorder=*/!isa<InsertElementInst>(Ops.front()) &&
14833           !R.doesRootHaveInTreeUses());
14834       R.buildExternalUses();
14835 
14836       R.computeMinimumValueSizes();
14837       InstructionCost Cost = R.getTreeCost();
14838       CandidateFound = true;
14839       MinCost = std::min(MinCost, Cost);
14840 
14841       LLVM_DEBUG(dbgs() << "SLP: Found cost = " << Cost
14842                         << " for VF=" << ActualVF << "\n");
14843       if (Cost < -SLPCostThreshold) {
14844         LLVM_DEBUG(dbgs() << "SLP: Vectorizing list at cost:" << Cost << ".\n");
14845         R.getORE()->emit(OptimizationRemark(SV_NAME, "VectorizedList",
14846                                                     cast<Instruction>(Ops[0]))
14847                                  << "SLP vectorized with cost " << ore::NV("Cost", Cost)
14848                                  << " and with tree size "
14849                                  << ore::NV("TreeSize", R.getTreeSize()));
14850 
14851         R.vectorizeTree();
14852         // Move to the next bundle.
14853         I += VF - 1;
14854         NextInst = I + 1;
14855         Changed = true;
14856       }
14857     }
14858   }
14859 
14860   if (!Changed && CandidateFound) {
14861     R.getORE()->emit([&]() {
14862       return OptimizationRemarkMissed(SV_NAME, "NotBeneficial", I0)
14863              << "List vectorization was possible but not beneficial with cost "
14864              << ore::NV("Cost", MinCost) << " >= "
14865              << ore::NV("Treshold", -SLPCostThreshold);
14866     });
14867   } else if (!Changed) {
14868     R.getORE()->emit([&]() {
14869       return OptimizationRemarkMissed(SV_NAME, "NotPossible", I0)
14870              << "Cannot SLP vectorize list: vectorization was impossible"
14871              << " with available vectorization factors";
14872     });
14873   }
14874   return Changed;
14875 }
14876 
14877 bool SLPVectorizerPass::tryToVectorize(Instruction *I, BoUpSLP &R) {
14878   if (!I)
14879     return false;
14880 
14881   if (!isa<BinaryOperator, CmpInst>(I) || isa<VectorType>(I->getType()))
14882     return false;
14883 
14884   Value *P = I->getParent();
14885 
14886   // Vectorize in current basic block only.
14887   auto *Op0 = dyn_cast<Instruction>(I->getOperand(0));
14888   auto *Op1 = dyn_cast<Instruction>(I->getOperand(1));
14889   if (!Op0 || !Op1 || Op0->getParent() != P || Op1->getParent() != P)
14890     return false;
14891 
14892   // First collect all possible candidates
14893   SmallVector<std::pair<Value *, Value *>, 4> Candidates;
14894   Candidates.emplace_back(Op0, Op1);
14895 
14896   auto *A = dyn_cast<BinaryOperator>(Op0);
14897   auto *B = dyn_cast<BinaryOperator>(Op1);
14898   // Try to skip B.
14899   if (A && B && B->hasOneUse()) {
14900     auto *B0 = dyn_cast<BinaryOperator>(B->getOperand(0));
14901     auto *B1 = dyn_cast<BinaryOperator>(B->getOperand(1));
14902     if (B0 && B0->getParent() == P)
14903       Candidates.emplace_back(A, B0);
14904     if (B1 && B1->getParent() == P)
14905       Candidates.emplace_back(A, B1);
14906   }
14907   // Try to skip A.
14908   if (B && A && A->hasOneUse()) {
14909     auto *A0 = dyn_cast<BinaryOperator>(A->getOperand(0));
14910     auto *A1 = dyn_cast<BinaryOperator>(A->getOperand(1));
14911     if (A0 && A0->getParent() == P)
14912       Candidates.emplace_back(A0, B);
14913     if (A1 && A1->getParent() == P)
14914       Candidates.emplace_back(A1, B);
14915   }
14916 
14917   if (Candidates.size() == 1)
14918     return tryToVectorizeList({Op0, Op1}, R);
14919 
14920   // We have multiple options. Try to pick the single best.
14921   std::optional<int> BestCandidate = R.findBestRootPair(Candidates);
14922   if (!BestCandidate)
14923     return false;
14924   return tryToVectorizeList(
14925       {Candidates[*BestCandidate].first, Candidates[*BestCandidate].second}, R);
14926 }
