14930 /// Model horizontal reductions.
14931 ///
14932 /// A horizontal reduction is a tree of reduction instructions that has values
14933 /// that can be put into a vector as its leaves. For example:
14934 ///
14935 /// mul mul mul mul
14936 ///  \  /    \  /
14937 ///   +       +
14938 ///    \     /
14939 ///       +
14940 /// This tree has "mul" as its leaf values and "+" as its reduction
14941 /// instructions. A reduction can feed into a store or a binary operation
14942 /// feeding a phi.
14943 ///    ...
14944 ///    \  /
14945 ///     +
14946 ///     |
14947 ///  phi +=
14948 ///
14949 ///  Or:
14950 ///    ...
14951 ///    \  /
14952 ///     +
14953 ///     |
14954 ///   *p =
14955 ///
14956 class HorizontalReduction {
14957   using ReductionOpsType = SmallVector<Value *, 16>;
14958   using ReductionOpsListType = SmallVector<ReductionOpsType, 2>;
14959   ReductionOpsListType ReductionOps;
14960   /// List of possibly reduced values.
14961   SmallVector<SmallVector<Value *>> ReducedVals;
14962   /// Maps reduced value to the corresponding reduction operation.
14963   DenseMap<Value *, SmallVector<Instruction *>> ReducedValsToOps;
14964   // Use map vector to make stable output.
14965   MapVector<Instruction *, Value *> ExtraArgs;
14966   WeakTrackingVH ReductionRoot;
14967   /// The type of reduction operation.
